SELECT * FROM film_stock
WHERE is_deleted = 0

    AND thickness = #{thickness}


    AND width = #{width}

ORDER BY create_time DESC

mapper.update:
UPDATE film_stock
SET available_area = available_area - #{lockArea},
    locked_area = locked_area + #{lockArea},
    available_rolls = available_rolls - #{lockRolls},
    locked_rolls = locked_rolls + #{lockRolls},
    update_time = NOW()
WHERE id = #{id}
  AND available_area >= #{lockArea}
  AND available_rolls >= #{lockRolls}

UPDATE film_stock
SET available_area = available_area + #{unlockArea},
    locked_area = locked_area - #{unlockArea},
    available_rolls = available_rolls + #{unlockRolls},
    locked_rolls = locked_rolls - #{unlockRolls},
    update_time = NOW()
WHERE id = #{id}
  AND locked_area >= #{unlockArea}
  AND locked_rolls >= #{unlockRolls}

UPDATE film_stock
SET total_area = total_area - #{outArea},
    locked_area = locked_area - #{outArea},
    total_rolls = total_rolls - #{outRolls},
    locked_rolls = locked_rolls - #{outRolls},
    update_time = NOW()
WHERE id = #{id}
  AND locked_area >= #{outArea}
  AND locked_rolls >= #{outRolls}
